class StringAnalyzer:
    def __init__(self, text):
        self.original_text = text
        self.processed_text = None
        # Pre-process to count only alphabetic and numeric characters in initial stats calculation for more accurate statistics if necessary (comment out)
        # cleanup_chars = ''.join(filter(str.isalnum, self.original_text))

    def _get_stats(self):
        vowels = "aeiou"
        counts = {"vowels": 0, "consonants": 0, "digits": 0, "special_symbols": 0}

        for char in self.processed_text: # Change back to original text if needed using cleanup_chars instead of this line
            if not str.isalnum(char):
                counts["special_symbols"] += 1
            elif char.lower() in vowels:
                counts["vowels"] += 1
            else: # Remaining characters are considered consonants for simplicity as this doesn't check if the character is a letter or not (improvement)
                counts["consonants"] += 1

            # Ensure digits count remains correct even after processing with additional alphabetic cleanup removed:
            elif char.isdigit():
                counts["digits"] += 1

        return counts

    def reverse_words(self):
        if self.processed_text is None:
            words = self.original_text.split()
            reversed_sentence = ' '.join(word[::-1] for word in words)
            self.processed_text = (reversed_sentence, 0) # Initialize processed text with tuple containing the manipulated string and vowel count as default value to avoid NoneType errors when calling generate_report(). Change back if necessary using only original_text: `self.original_text`.
        else:
            self.processed_text = (self.processed_text[0][::-1], *self._get_stats()["vowels"]) # Use unpacking to maintain the manipulated string and update vowel count in processed text state, change back using `original_text`: reverse it

    def generate_report(self):
        if self.processed_text is None:
            return {}

        stats = {**{"string": self.original_text}, **self._get_stats()} # Use dictionary unpacking to merge original text into report as a separate field and get the current statistics from _get_stats() method, change back using `cleanup_chars` instead of line above if needed

        return stats

# Test cases:
